#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n, d;
    scanf("%d %d", &n, &d);

    int *costs = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &costs[i]);
    }

    qsort(costs, n, sizeof(int), compare);

    int m;
    scanf("%d", &m);

    int profit = 0;

    if (m <= n) {
        for (int i = 0; i < m; i++) {
            profit += costs[i];
        }
    } else {
        for (int i = 0; i < n; i++) {
            profit += costs[i];
        }
        profit -= (m - n) * d;
    }

    printf("%d\n", profit);
    free(costs);
    return 0;
}
